def _deserialize_from_disk(self, raw: bytes) -> Any:
    """Reverse `_serialize_for_disk`, transparently handling legacy header-less blobs."""
    if not (isinstance(raw, (bytes, bytearray)) and raw[:4] == _MAGIC_HEADER):
        # Legacy entry written before compression support existed: a raw pickle blob.
        return pickle.loads(raw)

    codec_byte = raw[4]
    payload = bytes(raw[5:])
    if codec_byte == _CODEC_GZIP:
        payload = gzip.decompress(payload)
    elif codec_byte == _CODEC_ZLIB:
        payload = zlib.decompress(payload)
    elif codec_byte != _CODEC_NONE:
        raise ValueError(f"Unknown cache compression codec byte: {codec_byte!r}")
